sys_script_include.script:
var PatientUtils = Class.create();
PatientUtils.prototype = {
    initialize: function() {
    },
	getPatientDetailsById : function(patientId){
		var res = {};
		var gr = new GlideRecord('u_patient_record');
		if(gr.get('u_number',patientId)){
			res.sys_id = gr.getUniqueValue();
			res.name = gr.getValue('u_first_name');
			res.DOB = gr.getValue('u_date_of_birth');
			res.gender = gr.getValue('u_gender');
		}
		return res;
	},

	checkVip : function(patientId){
		var gr = new GlideRecord('u_patient_record');
		if(gr.get('u_number',patientId)){
			return gr.getValue('u_vip')==true || gr.getValue('u_vip')=='true';
		}
		return false;
	},

	getAge : function(patientId){
		var gr = new GlideRecord('u_patient_record');
		if(gr.get('u_number',patientId)){
			var dobstr = gr.getValue('u_date_of_birth');
			var dob = new GlideDate();
			dob.setValue(dobstr);
			var now = new GlideDate();

			var dobinmills = dob.getNumericValue();
			var nowinmills = now.getNumericValue();

			var diffinmills = Math.abs(dobinmills-nowinmills);
			var ageinyrs = Math.floor(diffinmills/(1000*60*60*24*365.25));

			return ageinyrs;
		}
	},

	getPatientAppointments : function(patientSysId){
		var gr = new GlideRecord('u_appointment');
		gr.addQuery('u_patient_id',patientSysId);
		gr.query();
		var res = [];
		while(gr.next()){
			res.push({
				AppointmentId : gr.getValue('number'),
				AppointmentDate : gr.getValue('u_appointment_date'),
				DoctorId : gr.getDisplayValue('u_doctor')
			});
		}
		return res;
	},

	getPatientMedication : function(patientSysId){
		var gr = new GlideRecord('u_medication');
		gr.addQuery('u_patient_id',patientSysId);
		gr.query();
		var med = [];
		while(gr.next()){
			med.push({
				MedicationId : gr.getValue('number'),
				MedicationName : gr.getValue('u_medication_name'),
				Frequency: gr.getValue('u_frequency')
			});
		}
		return med;
	},

	getPatientLabTest: function(patientSysId){
		var gr = new GlideRecord('u_lab_test');
		gr.addQuery('u_patient_id',patientSysId);
		gr.query();
		var res = [];
		while(gr.next()){
			res.push({
				TestId : gr.getValue('number'),
				TestType : gr.getValue('u_test_type'),
				Result : gr.getValue('u_result')
			});
		}
		return res;
	},

    type: 'PatientUtils'
};
